<template>
  <div id="add_button" @click="add_item">
    +
  </div>
</template>

<style>
#add_button {
  width: calc(100% - 16px);
  margin: 2px;
  margin-left: 7px;
  border: 1px solid grey;
  display: flex;
  justify-content: center;
  align-items: center;
  height: 32px;
}
</style>

<script>
export default {
  props: {
    type: String,
  },
  data() {
    return {
      hero: {
        group_id: -1,
        name: "A New Hero!",
        locale_id: -1,
        locale_x: -1,
        locale_y: -1,
        hp: 10,
        max_hp: 10,
        unique: true,
        portrait:
          "data:image/png;base64,",
        marker:
          "data:image/png;base64,",
        visible: false,
      },
      npc: {
        group_id: -1,
        name: "A New NPC!",
        locale_id: -1,
        locale_x: -1,
        locale_y: -1,
        hp: 10,
        max_hp: 10,
        unique: true,
        portrait:
          "data:image/png;base64,",
        marker:
          "data:image/png;base64,",
        visible: false,
      },
      enemy: {
        group_id: -1,
        name: "A New Enemy!",
        locale_id: -1,
        locale_x: -1,
        locale_y: -1,
        hp: 10,
        max_hp: 10,
        unique: true,
        portrait:
          "data:image/png;base64,",
        marker:
          "data:image/png;base64,",
        visible: false,
      },
      group: {
        name: "A New Group",
        locale_id: -1,
        locale_x: -1,
        locale_y: -1,
        marker:
          "data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAACAAAAAgCAYAAABzenr0AAAAmElEQVR4nO2XSw6AIAxEe/9LuXXJLTyGCkYXBPqxVGIyTRo3w/RBu7C0LhvlTIk+zbuuWPyM3ZMShEiaTd6GBFD8tQDWm4cAMJoSljNDATxnAAAAAAAAAAD4HwBnSte/QBwAZ6zVuQDqr0XjBqjb0LttSx8yhFyh4S/A9ZybiSEAlta0NFMBVD4AmA7g2Yy1k97LZzueuZ4fOhvlcGElvXEAAAAASUVORK5CYII=",
        visible: false,
      },
      locale: {
        id: 0,
        overworld: true,
        locale_id: 0,
        locale_x: 0,
        locale_y: 0,
        name: "A New Locale!",
        map:
          "data:image/png;base64,",
        marker:
          "data:image/png;base64,",
        visible: true,
        marker_img: {},
        map_img: {},
      },
      event: {
        id: 0,
        name: "A New Event!",
        locale_id: -1,
        locale_x: -1,
        locale_y: -1,
        marker:
          "data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAACAAAAAgCAYAAABzenr0AAAAnElEQVR4nO2X0Q2AIAxE2cYxHc1fN3EM1A+MIRa8u2g1KUn/gHuXtpCmeVrSHnkcXo2iC4tvK7cChYDFewuFoMRN9wQEDNC6/M6eAAgAGcASeLwLeg4Z9wFAA9RCbP5hAMsp6z4AJIDzr8jmnwKoHSvuA4AGuKoF+h72YIFQxP8N4JoC1yL8zEvoBuCeghpCLkJlMlbb8JiOPcfzFRcB7kmsPD+PAAAAAElFTkSuQmCC",
        visible: true,
        marker_img: {},
      },
    };
  },
  mounted() {},
  methods: {
    add_item() {
      const scope_this = this;
      var new_item = {};
      if (this.type == "heroes") {
        new_item = { ...scope_this.hero };
        new_item.marker_img = new Image();
        new_item.marker_img.src = new_item.marker;
        new_item.portrait_img = new Image();
        new_item.portrait_img.src = new_item.portrait;
      } else if (this.type == "npcs") {
        new_item = { ...scope_this.npc };
        new_item.marker_img = new Image();
        new_item.marker_img.src = new_item.marker;
        new_item.portrait_img = new Image();
        new_item.portrait_img.src = new_item.portrait;
      } else if (this.type == "enemies") {
        new_item = { ...scope_this.enemy };
        new_item.marker_img = new Image();
        new_item.marker_img.src = new_item.marker;
        new_item.portrait_img = new Image();
        new_item.portrait_img.src = new_item.portrait;
      } else if (this.type == "groups") {
        new_item = { ...scope_this.group };
        new_item.marker_img = new Image();
        new_item.marker_img.src = new_item.marker;
      } else if (this.type == "locales") {
        new_item = { ...scope_this.locale };
        new_item.marker_img = new Image();
        new_item.marker_img.src = new_item.marker;
        new_item.map_img = new Image();
        new_item.map_img.src = new_item.map;
      } else if (this.type == "events") {
        new_item = { ...scope_this.event };
        new_item.marker_img = new Image();
        new_item.marker_img.src = new_item.marker;
      }
      var open_me = this.$parent.$parent.data.controller.create(
        this.type,
        new_item
      );
      this.$parent.close_item();
      setTimeout(() => {
        scope_this.$parent.open(scope_this.type, open_me.id);
      }, 1);
    },
  },
};
</script>
